"use client"

import { useSearchParams, useRouter } from "next/navigation"
import { useEffect, useState } from "react"

const grades = ["6", "7", "8", "9", "10", "11", "12", "Đại học", "Khác"]

export default function InforLogin() {
    const searchParams = useSearchParams()
    const router = useRouter()

    const tab = searchParams.get("tab") || "otp"

    const [otp, setOtp] = useState("")
    const [provinces, setProvinces] = useState<any[]>([])

    const [form, setForm] = useState({
        province: "",
        school: "",
        grade: "",
        dob: ""
    })

    // 👉 fetch tỉnh
    useEffect(() => {
        fetch("https://34tinhthanh.com/api/provinces")
            .then(res => res.json())
            .then(data => setProvinces(data.data || []))
    }, [])

    const handleVerify = () => {
        if (otp.length < 6) return

        router.push("/infor-login?tab=infor")
    }

    const handleChange = (e: any) => {
        const { name, value } = e.target

        setForm(prev => ({
            ...prev,
            [name]: value
        }))
    }

    return (
        <div className="w-full h-screen bg-black flex items-center justify-center">
            <div className="w-[90%] max-w-md border border-white/10 rounded-2xl bg-white/[0.02] backdrop-blur-md p-6">

                {/* STEP OTP */}
                {tab === "otp" && (
                    <>
                        <h1 className="text-white text-xl font-semibold text-center">
                            Nhập mã OTP
                        </h1>

                        <input
                            value={otp}
                            onChange={(e) => setOtp(e.target.value)}
                            maxLength={6}
                            placeholder="••••••"
                            className="mt-6 w-full text-center tracking-[10px] text-white text-lg bg-transparent border border-zinc-700 rounded-xl py-3 outline-none focus:border-blue-500"
                        />

                        <button
                            onClick={handleVerify}
                            className="mt-5 w-full rounded-xl bg-blue-500 text-white py-3 hover:bg-blue-600 transition"
                        >
                            Xác nhận
                        </button>
                    </>
                )}

                {/* STEP INFOR */}
                {tab === "infor" && (
                    <>
                        <h1 className="text-white text-xl font-semibold text-center">
                            Thông tin cá nhân
                        </h1>

                        <div className="mt-6 space-y-4">

                            {/* Tỉnh */}
                            <select
                                name="province"
                                onChange={handleChange}
                                className="w-full px-4 py-3 rounded-xl bg-black border border-zinc-700 text-white outline-none"
                            >
                                <option value="">Chọn tỉnh</option>
                                {provinces.map((p: any) => (
                                    <option key={p.code} value={p.name}>
                                        {p.name}
                                    </option>
                                ))}
                            </select>

                            {/* Trường (input) */}
                            <input
                                name="school"
                                placeholder="Nhập tên trường"
                                onChange={handleChange}
                                className="w-full px-4 py-3 rounded-xl bg-transparent border border-zinc-700 text-white outline-none focus:border-blue-500"
                            />

                            {/* Lớp */}
                            <select
                                name="grade"
                                onChange={handleChange}
                                className="w-full px-4 py-3 rounded-xl bg-black border border-zinc-700 text-white outline-none"
                            >
                                <option value="">Chọn lớp</option>
                                {grades.map((g) => (
                                    <option key={g} value={g}>
                                        {g}
                                    </option>
                                ))}
                            </select>

                            {/* Ngày sinh */}
                            <input
                                type="date"
                                name="dob"
                                onChange={handleChange}
                                className="w-full px-4 py-3 rounded-xl bg-transparent border border-zinc-700 text-white outline-none focus:border-blue-500"
                            />
                        </div>

                        <button
                            className="mt-6 w-full rounded-xl bg-blue-500 text-white py-3 hover:bg-blue-600 transition"
                        >
                            Hoàn tất
                        </button>
                    </>
                )}
            </div>
        </div>
    )
}